-- Enrichment marathon batch: Blender, Bloomreach, Blue River Technology, Bluefish, BlueJ, BlueMail, Blynk, Bold Commerce

-- ── Blender ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Blender is a free, open-source 3D creation suite covering modeling, sculpting, rigging, animation, simulation, rendering, compositing, motion tracking, and video editing, maintained by the nonprofit Blender Foundation.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1994, founded_year),
  company_size = COALESCE($q$About 15 employees at the Blender Institute, plus a large global contributor community$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Blender: Free Open-Source 3D Creation Suite$q$, seo_title),
  seo_meta_description = COALESCE($q$Blender is a free, open-source 3D suite for modeling, animation, VFX, rendering, and video editing, backed by the nonprofit Blender Foundation.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Blender is a free and open-source 3D creation suite maintained by the Blender Foundation, a Dutch nonprofit organization headquartered in Amsterdam, Netherlands. Its origin traces to January 1994, when Ton Roosendaal began writing the software's first source code as an in-house tool at the Dutch animation studio NeoGeo, a date Blender.org itself calls the software's official birthday. In 1998 Roosendaal founded Not a Number Technologies (NaN) to develop and distribute Blender commercially, but NaN went bankrupt in 2002. A crowdfunding campaign that year raised 100,000 euros to buy back the source code from NaN's investors, and Blender was released under the GNU General Public License on October 13, 2002, the same year the Blender Foundation was formally established to steward its future development. Blender is completely free to download and use, with no licensing fees or paid tiers for the core application, and it runs on Windows, macOS, and Linux. It covers the entire 3D production pipeline in one application: polygon modeling, digital sculpting, UV unwrapping and texture painting, rigging and skeletal animation, particle and physics simulation for cloth, fluid, smoke, fire, and rigid or soft bodies, two built-in render engines (the path-traced Cycles engine and the real-time EEVEE engine), a node-based compositor, camera and object motion tracking, a non-linear video sequence editor, and Grease Pencil for 2D animation inside a 3D workspace. Geometry Nodes adds a node-based system for procedural modeling and scattering, and a Python API allows scripting, custom tooling, and third-party add-on development, with both free and paid add-ons distributed through the Blender Extensions platform. Blender is used across film, game development, visual effects, product visualization, architecture, and education, and the Blender Foundation produces periodic open movie projects to test and showcase new features under real production conditions. Governance sits with the Blender Foundation, which owns the Blender trademark and coordinates a roughly 15-person Blender Institute team in Amsterdam alongside a large volunteer and corporate developer community; companies and individuals fund ongoing core development through the Blender Development Fund and corporate membership programs. Because there is no purchase cost, Blender is widely adopted by students, hobbyists, freelancers, and small studios, and increasingly by larger production pipelines that use it alongside or instead of commercial packages like Maya, 3ds Max, or Cinema 4D. Blender releases on a regular cadence with periodic Long-Term Support (LTS) versions intended for production stability, and the software's most recent major cycles have focused on performance improvements to Cycles and EEVEE, a rebuilt Grease Pencil toolset, and continued expansion of Geometry Nodes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '62e5423f-7b35-4d89-942b-e5a1783055ad';

