-- ── Bloomreach ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bloomreach is an AI-driven commerce experience platform combining product search and merchandising (Discovery), marketing automation and customer data (Engagement), and headless content management (Content) for enterprise retail brands.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom quote-based pricing$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$1,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bloomreach: AI Commerce Experience Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Bloomreach powers e-commerce search, merchandising, marketing automation, and headless content for enterprise retail brands with built-in AI.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bloomreach was founded in 2009 by Raj De Datta and Ashutosh Garg and is headquartered in Mountain View, California. De Datta, previously an entrepreneur-in-residence at Mohr Davidow Ventures, and Garg, a former Google engineer who worked on search quality, built the company to close what they described as a relevance gap in e-commerce: search engines like Google could find information generally, but individual retailers struggled to help shoppers find products within their own catalogs. Bloomreach launched its first product, an SEO-focused tool, in 2012, and expanded from there into site search, merchandising, and personalization. Two acquisitions reshaped the company's product portfolio: the 2016 acquisition of Amsterdam-based Hippo CMS added headless content management, later rebranded as Bloomreach Content, and the 2021 acquisition of Exponea added real-time customer data platform and marketing automation capabilities, rebranded as Bloomreach Engagement. That expansion, supported by a $150 million investment from Sixth Street at a roughly $900 million valuation followed by an additional $175 million round, pushed Bloomreach's valuation to approximately $2.2 billion by early 2022. Today Bloomreach organizes its offering around four products: Discovery, an AI-powered search and merchandising engine for product catalogs; Engagement, a marketing automation and customer data platform for email, SMS, and personalized campaigns; Content, a headless CMS for building and managing commerce content and experiences; and Clarity, an AI-driven conversational shopping assistant. Loomi, Bloomreach's generative AI layer, is built into every product at no additional charge, according to the company. Bloomreach serves more than 850 global brands, including Albertsons, Staples, Bosch, Puma, FC Bayern Munchen, and Marks and Spencer, and reports roughly 219.5 million dollars in annual revenue. Pricing is not published on a fixed rate card; Bloomreach instead prices subscriptions around a module fee plus usage, so customers pay only for the products they use (Discovery, Engagement, Content, or some combination), with usage-based pricing tied to factors like indexed product catalog size, annual API call volume, and campaign or event volume. Publicly referenced figures include an Engagement starter price around 19,020 dollars per year through the Shopify App Store for smaller merchants, with typical non-Shopify Engagement deployments ranging from roughly 40,000 to 250,000-plus dollars annually, and full-platform (Discovery plus Engagement plus Content) deals commonly cited in the range of 150,000 to 400,000-plus dollars per year for larger enterprise customers. Competitors in this space include Algolia and Coveo in search, Klaviyo and Braze in marketing automation, and Contentful and Adobe Experience Manager in headless content, though Bloomreach's differentiation is bundling all three categories under one commerce-focused platform with built-in AI.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd3de63cc-8964-42d0-a306-17d133456303';

