-- ── Blue River Technology ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Blue River Technology is a Silicon Valley agricultural technology company, now a subsidiary of John Deere, that builds computer vision and machine learning systems, most notably the See and Spray precision spraying technology, for row-crop farming.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Over 80 employees (some estimates cite a broader range as a John Deere subsidiary)$q$, company_size),
  headquarters = COALESCE($q$Santa Clara, California, United States (originally founded in Sunnyvale, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Blue River Technology: John Deere's See and Spray AI$q$, seo_title),
  seo_meta_description = COALESCE($q$Blue River Technology builds the computer vision behind John Deere's See and Spray precision agriculture system, acquired for 305 million dollars in 2017.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Blue River Technology was founded in 2011 by two Stanford graduate students, Jorge Heraud and Lee Redden, who met during a Lean LaunchPad course and decided to apply robotics, computer vision, and machine learning to make farming more sustainable. Heraud had previously led precision agriculture at Trimble, while Redden was pursuing graduate studies in computer vision and machine learning applied to robotics. The pair tested early prototypes in California's Central Valley with support from friends, family, and a National Science Foundation grant, then raised a 3.1 million dollar Series A led by Khosla Ventures in 2012 to move from garage research and development into a dedicated lab. Blue River's core innovation became See and Spray, a system that mounts computer vision and machine learning models onto agricultural sprayers to distinguish individual crop plants from weeds in real time and apply herbicide only where it is needed, rather than spraying an entire field uniformly. In September 2017, John Deere acquired Blue River Technology for approximately 305 million dollars, and the company has operated as a John Deere subsidiary ever since, continuing to develop its computer vision and robotics technology under the Deere umbrella while retaining a degree of startup-style autonomy in its engineering culture. The See and Spray technology has expanded significantly since the acquisition: a Premium version debuted for cotton in 2020 and expanded to corn and soybeans by 2022, and in 2024 John Deere launched the more affordable See and Spray Select, a retrofit kit for existing sprayers that broadened adoption beyond customers buying new equipment. By 2025, John Deere reported that See and Spray had reduced herbicide use by nearly 50 percent and saved an estimated 31 million gallons of herbicide across roughly 5 million acres. Blue River Technology today describes itself as developing intelligent machinery combining computer vision, robotics, and machine learning across agriculture and adjacent heavy industries such as construction and mining, framing its technology as the eyes, brains, and hands of a machine. The company is headquartered in Santa Clara, California (having originally been founded in nearby Sunnyvale), and continues to hire for roles in machine learning, computer vision, and field applications, indicating it remains an active operating subsidiary rather than a shuttered or fully absorbed division. Because Blue River's technology is delivered as an embedded feature of John Deere agricultural equipment rather than as standalone, self-serve software, there is no public consumer pricing; access comes through purchasing or retrofitting compatible John Deere sprayers via Deere's dealer network. Blue River's closest comparisons are other agricultural computer vision and robotics ventures such as Carbon Robotics and Bilberry, though Blue River is distinguished by its direct integration into John Deere's equipment lineup and dealer and service infrastructure at global scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '550831fa-f6ac-49ce-8f68-9bb633fdd5ec';

