-- ── Bluefish ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bluefish is a free, open-source, cross-platform text editor built for web and script development, supporting HTML and more than 30 programming and markup languages.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1998, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bluefish: Free Open-Source HTML and Code Editor$q$, seo_title),
  seo_meta_description = COALESCE($q$Bluefish is a free, open-source text editor for web developers, supporting HTML, PHP, JavaScript, Python, and more than 30 other languages.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bluefish is a free and open-source text editor built specifically for programmers and web developers, started in 1998 by Chris Mazuc and Olivier Sessink to give web development professionals a fast, capable editor on Linux desktops. The project quickly became part of major Linux distributions, appearing in Debian Potato in 2000, Knoppix 2.1, and the first release of Fedora. Bluefish's development has gone through several major branches: the 1.0.x series released in 2005 introduced a new logo and stabilized the core editor; the 2.0.x series was a significant rewrite that moved to the GTK 2 GtkTextView widget and introduced a new syntax scanning engine based on a deterministic finite automaton; and the current 2.2.x and later branches support both GTK 2 and GTK 3 toolkits. As of mid-2026, the most recent release is version 2.4.2, which added icon theme detection with built-in Breeze theme support and fixed a critical crash related to UTF-8 encoding handling; version 2.4.1 had already made Bluefish's side-by-side editing mode fully stable. Bluefish is released under the GNU General Public License and runs on Linux, macOS, Windows, FreeBSD, and OpenBSD, distributed as free software with no purchase price, subscription, or paid tier of any kind; there is no company behind it, only an open-source community led by its original developers and ongoing contributors, so it has no headquarters or employee count in the traditional sense. Functionally, Bluefish is designed to start in milliseconds and comfortably handle projects with a thousand or more open files, and it supports syntax highlighting and code intelligence for more than 30 markup and programming languages, including HTML, PHP, JavaScript, Python, C, Java, YAML, and XML. It can open, edit, and save files directly on remote servers over FTP, SFTP, FTPS, HTTP, HTTPS, and WebDAV, which lets web developers work directly against a live server without a separate file transfer step. Bluefish supports regular expressions in its search-and-replace functionality, a feature not all lightweight editors offer, and it ships with preconfigured external tool integrations for static code analysis and markup validation, such as lint-style syntax and markup checkers. Additional capabilities include project management for organizing multi-file websites or codebases, Zencoding/Emmet-style shorthand expansion for quickly generating HTML markup, and a highly customizable interface. Because it is lightweight, fast, and free, Bluefish is commonly used by web developers, students, and Linux users who want a capable code editor without the resource overhead of a full IDE, and it remains especially popular in Linux and open-source software communities where it has been bundled or packaged for over two decades.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4a95891a-9b70-49b6-9aa5-aacb25ea2e3e';

