-- ── BlueJ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BlueJ is a free, education-focused integrated development environment for Java that visualizes class structure and lets students interactively create and test objects, originally developed at the University of Kent and Monash University.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom (maintained by King's College London)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BlueJ: Free Java IDE for Learning Programming$q$, seo_title),
  seo_meta_description = COALESCE($q$BlueJ is a free Java IDE built for teaching, with visual class diagrams and interactive objects, from the University of Kent and Monash University.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BlueJ is a free, education-focused integrated development environment for the Java programming language, with development started in 1999 by Michael Kolling and John Rosenberg at Monash University in Australia as a successor to an earlier teaching system called Blue. BlueJ was first released on August 23, 1999, and later became closely associated with the University of Kent in the United Kingdom, where it supported introductory object-oriented programming modules; it is now maintained by King's College London with support from Oracle. James Gosling, the creator of Java, has publicly praised BlueJ, calling it one of his favorite IDEs. BlueJ's central design goal is to lower the barrier to learning object-oriented programming by making class structure and object behavior visible and directly interactive rather than abstract. Its main screen displays an application's classes as a UML-like diagram, and from that diagram, students can create objects interactively, inspect their internal state, call methods on them directly, and pass objects as parameters to other method calls, all without writing a full test harness or main method first. This interactive object bench, combined with a Code Pad that lets users evaluate Java expressions on the fly without compiling a full program, functions as a graphical shell or REPL for Java that is specifically designed for teaching. BlueJ also includes an integrated source code editor with scope coloring, which visually highlights nested code blocks to help beginners understand program structure, along with a standard debugger. Early evaluations of BlueJ at Monash University found that students using it developed a stronger practical understanding of object-oriented programming concepts than students using C++-based teaching environments, attributed in part to its simplified error handling and object visualization. BlueJ is completely free to download and use, distributed under the GNU General Public License version 2 with the Classpath Exception, with copyright held jointly by Michael Kolling and John Rosenberg; there is no commercial licensing tier. As of mid-2026, the current release is version 6.0.0, published July 1, 2026, which added support for the Kotlin programming language alongside Java, expanding BlueJ's use beyond pure Java instruction. The application requires a 64-bit operating system, supporting Windows 8 or later, macOS 11 or later on both Apple Silicon and Intel processors, Ubuntu or Debian 20.04 or later, and generic Java or JavaFX 21 environments; users on older 32-bit systems can still run the legacy 4.1.4 build. BlueJ has been adopted by millions of learners and is widely integrated into secondary school and university introductory programming curricula worldwide, positioning it primarily as a teaching tool rather than a production-grade development environment, in contrast to professional IDEs like IntelliJ IDEA, Eclipse, or NetBeans.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '40873439-74d5-4c5a-9d8b-5e7348a903a9';

