-- ── Bold Commerce ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bold Commerce is a Winnipeg-based e-commerce technology company known for its suite of Shopify apps, including Bold Subscriptions, Bold Checkout, and Bold Upsell, plus composable commerce infrastructure for recurring revenue.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for eligible small stores; paid plans from around $24.99/month plus a transaction fee$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Winnipeg, Manitoba, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bold Commerce: Shopify Subscriptions and Checkout Apps$q$, seo_title),
  seo_meta_description = COALESCE($q$Bold Commerce powers Shopify apps like Bold Subscriptions, Checkout, and Upsell, plus composable commerce tools, used by over 760,000 merchants.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bold Commerce was founded in 2012 in a basement in Winnipeg, Manitoba, Canada, by four co-founders: Jay Myers, Stefan Maynard, Eric Boisjoli, and Yvan Boisjoli. Myers, who had been selling his family's archery products online since 1998, identified a need for better tools to improve the e-commerce experience on the then-young Shopify platform, and the team's first app, Product Upsell, quickly gained traction. All four founders initially held full-time jobs elsewhere and transitioned into Bold Commerce one by one between October 2012 and March 2013 as the business grew. The company remained bootstrapped until its first outside funding round in 2019, and later raised 35 million dollars from investors including OMERS Ventures, the venture capital arm of the Ontario Municipal Employees Retirement System, funding that supported plans to hire around 100 additional staff. Bold Commerce remains headquartered in Winnipeg, at 50 Fultz Boulevard, and employs an estimated 201 to 500 people, with staff spread across North America, Europe, and Asia. The company describes itself as 'the repeat commerce company,' focused on helping Shopify merchants increase customer lifetime value by driving repeat purchases and higher-value transactions. Its product suite centers on six core apps: Bold Subscriptions for recurring orders and subscription billing, Bold Checkout for customizable, high-conversion Shopify checkout experiences, Bold Upsell for cart and post-purchase upsell offers, Bold Discounts for promotional pricing rules, Bold Custom Pricing for tiered or negotiated pricing, Bold Memberships for gated content and membership tiers, and rePete, a reorder-nudging tool that prompts customers to repurchase consumable products. Bold holds Shopify Plus certification and describes itself as the first Shopify front-end app developer, reflecting its long tenure building on the Shopify App Store; the company reports that more than 760,000 online merchants have installed apps it has built, and that its Subscriptions app alone powers more than 41,000 subscription brands. On pricing, Bold Subscriptions offers a free option for stores generating less than 100 dollars per month in subscription revenue, plus a 90-day free trial variant for new subscription businesses; the entry paid tier costs 24.99 dollars per month plus a 2 percent transaction fee for stores generating under 2,500 dollars per month in subscription revenue, with pricing scaling up through additional tiers as subscription revenue grows, and custom Enterprise pricing available for businesses generating over 1 million dollars in annual subscription revenue. Bold's other apps, such as Checkout and Upsell, are typically priced and sold separately through the Shopify App Store rather than bundled into a single flat subscription. Bold Commerce's primary customers are Shopify and Shopify Plus merchants ranging from small direct-to-consumer brands launching their first subscription program up to larger, high-volume retailers needing a highly customizable checkout experience; its competitors include Recharge and Skio in subscriptions, and Shopify's own native checkout customization tools for merchants who do not need Bold's additional layer of functionality.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e3d6c369-5ccc-4a69-87aa-439e03e26dda';

