INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Modeling and Sculpting$q$, $q$Full polygon modeling toolkit plus a dedicated digital sculpting workflow with multi-resolution and dynamic topology tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Cycles and EEVEE Rendering$q$, $q$A path-traced Cycles engine for photorealistic output and a real-time EEVEE engine for fast previews and stylized rendering.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Rigging and Animation$q$, $q$Armature-based rigging, keyframe animation, and a non-linear animation editor for character and object animation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Physics and Simulation$q$, $q$Built-in simulation for cloth, fluid, smoke, fire, and rigid or soft body dynamics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Geometry Nodes$q$, $q$A node-based system for procedural modeling, scattering, and generating complex geometry non-destructively.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Grease Pencil 2D Animation$q$, $q$Draw and animate 2D artwork natively inside Blender's 3D workspace.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Video Sequence Editor$q$, $q$A built-in non-linear editor for cutting, compositing, and grading video directly inside Blender.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Python Scripting and Add-ons$q$, $q$A full Python API for custom tools and scripts, with a broad ecosystem of free and paid add-ons.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Completely free with no licensing fees, ever$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Covers modeling, animation, VFX, rendering, and video editing in one application$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Actively developed with frequent releases and a large open-source community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Cross-platform support for Windows, macOS, and Linux$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Extensible through a Python API and a large add-on ecosystem$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Widely taught in schools and universities due to its zero-cost licensing$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Steep learning curve for complete beginners to 3D$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Interface and shortcuts differ from industry-standard paid tools, requiring relearning for users coming from Maya or 3ds Max$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$No official enterprise support contract or SLA from the Blender Foundation itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Very large or complex production scenes can be harder to manage than in some dedicated commercial pipelines$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Third-party plugin quality and compatibility vary since add-ons are community-built$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Is Blender really free?$q$, $q$Yes. Blender is free and open-source software licensed under the GNU General Public License, with no purchase price, subscription fee, or feature paywall for the core application.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$What is Blender used for?$q$, $q$Blender is used for 3D modeling, sculpting, rigging, animation, simulation, rendering, compositing, motion tracking, and video editing across industries including film, games, VFX, product visualization, and architecture.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Does Blender include video editing?$q$, $q$Yes, Blender has a built-in non-linear Video Sequence Editor for cutting, compositing, and grading footage alongside its 3D tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$What render engines does Blender use?$q$, $q$Blender ships with two built-in render engines: Cycles, a path-traced engine for photorealistic output, and EEVEE, a real-time engine for fast previews and stylized rendering.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Is Blender good for beginners?$q$, $q$Blender is approachable for beginners thanks to extensive free tutorials and documentation, though its interface has a learning curve, especially for users coming from other 3D software.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Can Blender be used commercially?$q$, $q$Yes, Blender's GNU General Public License permits commercial use, including selling artwork, models, and animations made with the software.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$What operating systems does Blender support?$q$, $q$Blender runs natively on Windows, macOS, and Linux.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Who develops Blender?$q$, $q$Blender is developed and maintained by the Blender Foundation, a nonprofit organization based in Amsterdam, Netherlands, with support from the Blender Institute team and a large volunteer and corporate contributor community.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Independent 3D Art and Animation$q$, $q$Freelancers and hobbyists use Blender's full modeling-to-rendering pipeline without paying for software licenses.$q$, $q$Independent artists and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Film, VFX, and Game Production$q$, $q$Studios use Blender for modeling, rigging, simulation, and rendering as part of or alongside their production pipelines.$q$, $q$Film, VFX, and game studios$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$3D Education and Training$q$, $q$Schools and universities teach 3D modeling and animation with Blender because students can install it for free.$q$, $q$Students and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$Blender$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full 3D modeling, sculpting, and animation toolset","Cycles and EEVEE render engines","Video editing and 2D Grease Pencil animation","Python scripting and add-on support","No feature restrictions or paywalls"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$overview$q$, $q$What Is Blender$q$, 2, ARRAY[$q$Blender is a free, open-source 3D creation suite that handles modeling, sculpting, rigging, animation, simulation, rendering, compositing, motion tracking, and video editing inside a single application. It is developed and maintained by the Blender Foundation, a nonprofit organization based in Amsterdam, Netherlands.$q$, $q$The software's roots go back to January 1994, when Ton Roosendaal wrote its first source code as an in-house tool at the studio NeoGeo. After the commercial venture built around it, Not a Number Technologies, went bankrupt in 2002, a public crowdfunding campaign bought back the source code and released it under the GNU General Public License, and the Blender Foundation was founded the same year to guide its ongoing development.$q$, $q$Since then, Blender has grown from a niche open-source tool into an industry-recognized application used in film, game, and VFX production, alongside its long-standing base of students, hobbyists, and independent artists who rely on it because it costs nothing to use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Blender's toolset spans the full 3D pipeline: polygon and sculpt modeling, UV unwrapping and texture painting, rigging with an armature system, keyframe and non-linear animation, and a particle and physics engine for cloth, fluid, smoke, fire, and rigid or soft body simulation.$q$, $q$For output, Blender includes two production render engines, the path-traced Cycles engine for photorealistic rendering and the real-time EEVEE engine for fast previews and stylized looks, plus a node-based compositor for post-processing rendered footage. Geometry Nodes provides a procedural, node-based approach to modeling and scattering objects across a scene.$q$, $q$Beyond 3D, Blender includes camera and object motion tracking, a built-in non-linear video sequence editor for cutting and grading footage, and Grease Pencil, a 2D animation toolset that draws directly inside the 3D viewport. A Python API supports scripting and custom add-ons, extending Blender well past its out-of-the-box feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Blender itself carries no purchase price, subscription fee, or usage limit. It is distributed under the GNU General Public License, so anyone can download, use, modify, and even redistribute the software at no cost, on Windows, macOS, or Linux.$q$, $q$Development is funded through donations, corporate memberships in the Blender Development Fund, and revenue from the Blender Foundation's training platform and store rather than through charging end users for the software itself.$q$, $q$The only costs typically associated with Blender come from optional third-party add-ons sold through the Blender Extensions platform, or from separately purchased hardware and render-farm services some studios use to speed up Cycles rendering; none of this is required to use the core application.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62e5423f-7b35-4d89-942b-e5a1783055ad', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$AI-Powered Product Search$q$, $q$Discovery uses machine learning to rank and surface relevant products across large, complex catalogs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Merchandising Controls$q$, $q$Merchandisers can boost, bury, and rules-manage product placement in search and category results.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Marketing Automation and CDP$q$, $q$Engagement unifies customer data and powers email, SMS, and web personalization campaigns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Headless Content Management$q$, $q$Content provides a headless CMS for building commerce pages and experiences independent of the storefront framework.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Loomi Generative AI$q$, $q$An AI layer built into every Bloomreach product for content generation, recommendations, and personalization.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Clarity Conversational Shopping$q$, $q$An AI shopping assistant that helps customers find products through natural-language search and conversation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$SEO Tooling$q$, $q$Search engine optimization features rooted in Bloomreach's original 2012 product for improving organic product visibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Omnichannel Campaign Orchestration$q$, $q$Coordinate personalized campaigns across email, SMS, web, and other channels from a single customer data view.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Unifies search, merchandising, marketing automation, and content on one commerce-focused platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Loomi AI is included across every product at no extra charge$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Proven at enterprise scale with 850-plus global retail brands as customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Modular pricing lets customers adopt only the products they need$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Strong search relevance and personalization for very large product catalogs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Pricing is not published and can be expensive for smaller merchants$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Usage-based pricing tied to catalog size and API calls can create unpredictable costs as a business grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Full implementation typically requires professional services and technical integration work$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$The breadth of the platform means a steep learning curve to use it to its full potential$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Best suited to mid-market and enterprise retailers rather than very small stores$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$How much does Bloomreach cost?$q$, $q$Bloomreach does not publish fixed pricing. Costs are based on a module fee plus usage, with an Engagement starter tier around 19,020 dollars per year through the Shopify App Store and full-platform enterprise deals often ranging from 150,000 to 400,000-plus dollars annually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$What is Bloomreach used for?$q$, $q$Bloomreach is used by e-commerce and retail brands for product search and merchandising, marketing automation and customer data management, and headless content management.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$What is the difference between Bloomreach Discovery, Engagement, and Content?$q$, $q$Discovery powers product search and merchandising, Engagement handles marketing automation and customer data as a CDP, and Content is a headless CMS for managing commerce content and pages.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Does Bloomreach include AI?$q$, $q$Yes, Bloomreach's Loomi AI is built into every product, including Discovery, Engagement, Content, and Clarity, at no separate charge.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Who founded Bloomreach?$q$, $q$Bloomreach was founded in 2009 by Raj De Datta and Ashutosh Garg.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$What companies use Bloomreach?$q$, $q$Bloomreach serves more than 850 global brands, including Albertsons, Staples, Bosch, Puma, FC Bayern Munchen, and Marks and Spencer.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Is Bloomreach available for Shopify merchants?$q$, $q$Yes, Bloomreach Engagement is available through the Shopify App Store with a published starter price, while larger deployments are quoted directly by Bloomreach's sales team.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Does Bloomreach offer a free trial?$q$, $q$Bloomreach's public pricing pages direct prospective customers to request a quote or demo rather than offering a self-serve free trial.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Enterprise E-Commerce Search and Merchandising$q$, $q$Large retailers use Bloomreach Discovery to improve on-site search relevance and control merchandising across huge product catalogs.$q$, $q$Enterprise e-commerce merchandising teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Multichannel Marketing Automation$q$, $q$Marketing teams use Bloomreach Engagement's customer data platform to run personalized email, SMS, and web campaigns.$q$, $q$E-commerce marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Headless Content for Commerce Sites$q$, $q$Brands use Bloomreach Content to manage commerce content and landing pages independently of their storefront's front-end technology.$q$, $q$Digital and content teams at retail brands$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Discovery$q$, $q$Custom$q$, $q$Annual, usage-based$q$, NULL, $q$["AI product search and merchandising","Standard and Premium feature packages","Pricing based on indexed catalog size and API call volume"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Engagement$q$, $q$From approximately $19,020/year (Shopify App Store)$q$, $q$Annual$q$, NULL, $q$["Marketing automation and customer data platform","Email and SMS campaigns","Loomi AI included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$Content$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Grow, Scale, and Enterprise packages","Headless CMS for commerce content","Tailored to business size"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$overview$q$, $q$What Is Bloomreach$q$, 2, ARRAY[$q$Bloomreach is an AI-driven commerce experience platform founded in 2009 by Raj De Datta and Ashutosh Garg and headquartered in Mountain View, California. It was built to help online retailers make their own product catalogs as easy to search and discover as the open web, and has since expanded well beyond search into marketing automation and content management.$q$, $q$Two key acquisitions shaped the modern product line: Hippo CMS in 2016 became the foundation for Bloomreach Content, and Exponea in 2021 became the foundation for Bloomreach Engagement, a real-time customer data and marketing automation platform. Bloomreach now serves more than 850 global brands, including Albertsons, Staples, Bosch, Puma, and Marks and Spencer.$q$, $q$The company's AI layer, called Loomi, is embedded across every Bloomreach product, generating product descriptions, personalized recommendations, and conversational shopping experiences without a separate add-on fee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bloomreach Discovery handles product search, category pages, and merchandising, using AI-driven relevance ranking to help shoppers find products across large catalogs. Bloomreach Engagement covers email, SMS, and web personalization campaigns backed by a real-time customer data platform.$q$, $q$Bloomreach Content is a headless CMS that lets brands manage commerce content and page experiences independently of their storefront's front-end framework, while Bloomreach Clarity adds an AI-powered conversational shopping assistant that helps customers find products through natural-language interaction.$q$, $q$Because Loomi AI runs across all four products, features like AI-generated product content, personalized recommendations, and automated campaign optimization are available regardless of which specific Bloomreach module a customer adopts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3de63cc-8964-42d0-a306-17d133456303', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bloomreach does not publish a fixed price list. Subscriptions are structured around a module fee for each product a customer adopts (Discovery, Engagement, or Content) plus usage-based charges, so total cost depends on factors like catalog size, annual API call volume, and marketing event or message volume.$q$, $q$Publicly cited reference points include an Engagement starter tier around 19,020 dollars per year through the Shopify App Store for smaller merchants, with typical non-Shopify Engagement deployments ranging roughly from 40,000 to 250,000-plus dollars annually depending on scale.$q$, $q$For larger enterprises adopting the full platform across Discovery, Engagement, and Content, industry pricing estimates commonly fall in the range of 150,000 to 400,000-plus dollars per year; exact pricing requires contacting Bloomreach's sales team for a custom quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$See and Spray Computer Vision$q$, $q$Real-time onboard computer vision that distinguishes individual crop plants from weeds while spraying.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Targeted Herbicide Application$q$, $q$Sprays herbicide only where weeds are detected instead of applying it uniformly across an entire field.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$See and Spray Premium$q$, $q$A precision spraying product line covering cotton, corn, and soybean row crops.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$See and Spray Select$q$, $q$A retrofit kit launched in 2024 that adds precision spraying capability to existing sprayers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Edge-Based Machine Learning$q$, $q$Processes camera imagery and makes spraying decisions in real time on the machine rather than relying on off-site processing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$John Deere Equipment Integration$q$, $q$Built directly into John Deere sprayers and supported through Deere's dealer and service network.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Field-Scale Impact Reporting$q$, $q$John Deere reports aggregate herbicide savings data from See and Spray usage across millions of acres.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Meaningfully reduces herbicide use and cost for large row-crop operations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Proven at scale, with tens of millions of gallons of herbicide savings reported across millions of acres$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Backed by John Deere's manufacturing, dealer, and service infrastructure$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Combines deep robotics, computer vision, and machine learning expertise from a dedicated ag-tech team$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Retrofit option (See and Spray Select) extends the technology to farmers with existing sprayers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Not a standalone consumer software product; access requires John Deere equipment and a dealer relationship$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Pricing is not publicly published and varies by configuration and region$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Primarily suited to large-scale row-crop operations rather than small or diversified farms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Adoption depends on compatible sprayer hardware, limiting use for growers on other equipment brands$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Is Blue River Technology still an independent company?$q$, $q$No, Blue River Technology has operated as a subsidiary of John Deere since Deere acquired it in September 2017 for approximately 305 million dollars, though it continues to operate with a degree of startup-style autonomy.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$What does Blue River Technology do?$q$, $q$Blue River Technology develops computer vision, robotics, and machine learning systems for agriculture, most notably the See and Spray precision spraying technology used on John Deere equipment.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$What is See and Spray?$q$, $q$See and Spray is a system that uses onboard cameras and machine learning to distinguish crops from weeds in real time so herbicide is applied only where needed rather than across an entire field.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$How much herbicide does See and Spray save?$q$, $q$John Deere has reported that See and Spray reduced herbicide use by nearly 50 percent and saved an estimated 31 million gallons of herbicide across about 5 million acres in 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Can I buy Blue River Technology's software without John Deere equipment?$q$, $q$No, See and Spray is delivered as an integrated feature of John Deere sprayers or as a retrofit kit (See and Spray Select) for compatible existing sprayers, rather than as standalone software.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Who founded Blue River Technology?$q$, $q$Blue River Technology was founded in 2011 by Stanford graduate students Jorge Heraud and Lee Redden.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$When was Blue River Technology acquired by John Deere?$q$, $q$John Deere acquired Blue River Technology in September 2017 for approximately 305 million dollars.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Where is Blue River Technology headquartered?$q$, $q$Blue River Technology is headquartered in Santa Clara, California, United States, after originally being founded in nearby Sunnyvale, California.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Row-Crop Herbicide Spraying$q$, $q$Farmers growing cotton, corn, and soybeans use See and Spray Premium to reduce herbicide costs and environmental impact.$q$, $q$Row-crop farmers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Retrofitting Existing Sprayers$q$, $q$Growers with existing sprayer equipment add See and Spray Select to gain precision spraying capability without buying an entirely new machine.$q$, $q$Farmers with existing John Deere-compatible sprayers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$Agricultural Computer Vision R&D$q$, $q$Blue River's engineering team continues developing computer vision and robotics technology for future agricultural and heavy-industry applications under John Deere.$q$, $q$John Deere product and engineering teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$overview$q$, $q$What Is Blue River Technology$q$, 2, ARRAY[$q$Blue River Technology is an agricultural technology company founded in 2011 by Stanford graduate students Jorge Heraud and Lee Redden, built around applying computer vision and machine learning to make farming more precise and sustainable. Its best-known product, See and Spray, uses onboard cameras and machine learning models to tell crops apart from weeds in real time and spray herbicide only where it is needed.$q$, $q$In September 2017, John Deere acquired Blue River Technology for approximately 305 million dollars. The company has operated as a John Deere subsidiary since the acquisition, continuing its agricultural computer vision and robotics work while retaining a startup-style engineering culture within the larger Deere organization.$q$, $q$Blue River remains headquartered in Santa Clara, California, and continues to hire for machine learning, computer vision, and field application roles, indicating it remains an active part of John Deere's technology operations rather than a fully absorbed or discontinued division.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$See and Spray combines onboard cameras, edge computing, and machine learning models trained on agricultural imagery to differentiate individual crop plants from weeds while a sprayer moves through a field, triggering targeted herbicide application only where weeds are detected.$q$, $q$Since the John Deere acquisition, the technology has been packaged into multiple product tiers: See and Spray Premium, which debuted for cotton in 2020 and expanded to corn and soybeans by 2022, and See and Spray Select, launched in 2024 as a more affordable retrofit kit for existing sprayers.$q$, $q$The system integrates directly with John Deere sprayers and tractors, giving farmers real-time, in-field processing rather than requiring data to be sent off-site for analysis before spraying decisions are made.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('550831fa-f6ac-49ce-8f68-9bb633fdd5ec', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Blue River Technology does not sell standalone software with public, self-serve pricing. Its See and Spray technology is delivered as a feature of John Deere agricultural equipment, either factory-installed on new sprayers or added as a retrofit kit through See and Spray Select.$q$, $q$Pricing and configuration are handled through John Deere's dealer network and vary based on the specific sprayer model, acreage, and configuration a farm operation needs, so there is no published flat rate for the technology itself.$q$, $q$Farmers interested in See and Spray typically work with a local John Deere dealer to determine equipment compatibility, retrofit options, and financing rather than purchasing access directly from Blue River Technology.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Fast Startup and Large-File Handling$q$, $q$Launches in milliseconds and can comfortably manage projects with a thousand or more open files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$30-Plus Language Support$q$, $q$Syntax highlighting and code assistance for HTML, PHP, JavaScript, Python, C, Java, YAML, XML, and more.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Remote File Editing$q$, $q$Open, edit, and save files directly on remote servers over FTP, SFTP, FTPS, HTTP, HTTPS, and WebDAV.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Regular Expression Search and Replace$q$, $q$Advanced search-and-replace functionality that supports regular expressions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Project Management$q$, $q$Organize and manage multi-file websites or codebases within a single project view.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Zencoding and Emmet Support$q$, $q$Shorthand expansion for quickly generating HTML and CSS markup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Side-by-Side Editing$q$, $q$A stable split-view editing mode for comparing or editing multiple files at once.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Cross-Platform Availability$q$, $q$Runs natively on Linux, macOS, Windows, FreeBSD, and OpenBSD.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Completely free and open source under the GPL$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Extremely lightweight and fast, even with large numbers of open files$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Supports remote server editing over FTP, SFTP, and WebDAV without a separate upload step$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Broad language support covering more than 30 markup and programming languages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Long, stable development history dating back to 1998$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Interface looks dated compared to modern code editors like VS Code$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Lacks the extension marketplace and plugin ecosystem of more modern editors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$No built-in version control integration comparable to mainstream IDEs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Community-driven development means slower feature releases than commercially backed editors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Is Bluefish free?$q$, $q$Yes, Bluefish is entirely free and open-source software licensed under the GNU General Public License, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$What platforms does Bluefish support?$q$, $q$Bluefish runs on Linux, macOS, Windows, FreeBSD, and OpenBSD.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Can Bluefish edit files on a remote server?$q$, $q$Yes, Bluefish can open, edit, and save files directly on remote servers over FTP, SFTP, FTPS, HTTP, HTTPS, and WebDAV.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Who created Bluefish?$q$, $q$Bluefish was started in 1998 by Chris Mazuc and Olivier Sessink.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$How many languages does Bluefish support?$q$, $q$Bluefish supports syntax highlighting and code assistance for more than 30 markup and programming languages, including HTML, PHP, JavaScript, Python, and Java.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Is Bluefish still actively maintained?$q$, $q$Yes, Bluefish continues to receive updates, with version 2.4.2 released in mid-2026 adding icon theme detection and bug fixes.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Does Bluefish support regular expressions in search and replace?$q$, $q$Yes, Bluefish is one of the editors that supports regular expressions in its search-and-replace functionality.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Lightweight Web Development$q$, $q$Developers use Bluefish to write and edit HTML, CSS, PHP, and JavaScript without the overhead of a full IDE.$q$, $q$Web developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Direct Remote Server Editing$q$, $q$Developers edit files directly on live servers over FTP, SFTP, or WebDAV without a separate upload step.$q$, $q$Freelance and small-team web developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Linux Desktop Coding$q$, $q$Linux users adopt Bluefish as a fast, native code editor bundled with or available in most major Linux distributions.$q$, $q$Linux users and open-source contributors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$Bluefish$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full code editing feature set","Remote file editing over FTP, SFTP, and WebDAV","Support for 30-plus languages","No feature restrictions"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$overview$q$, $q$What Is Bluefish$q$, 2, ARRAY[$q$Bluefish is a free, open-source text editor built specifically for programmers and web developers. It was started in 1998 by Chris Mazuc and Olivier Sessink to give Linux users a fast, capable tool for building websites and writing code, and it quickly became part of major Linux distributions including Debian, Knoppix, and Fedora.$q$, $q$The project has gone through several major rewrites over its history, moving from its original 1.0.x series through a significant GTK 2-based rewrite in the 2.0.x branch to today's 2.2.x and later releases, which support both GTK 2 and GTK 3. The current stable release, version 2.4.2, was published in mid-2026.$q$, $q$Bluefish is released under the GNU General Public License and is maintained as a community open-source project rather than by a commercial company, meaning there is no purchase price, subscription, or company headquarters associated with it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bluefish is designed to be extremely fast, starting in milliseconds and handling projects with a thousand or more open files without slowing down. It supports syntax highlighting and code assistance for more than 30 markup and programming languages, including HTML, PHP, JavaScript, Python, C, Java, YAML, and XML.$q$, $q$One of Bluefish's standout capabilities is direct remote file editing: it can open, edit, and save files on a live server over FTP, SFTP, FTPS, HTTP, HTTPS, and WebDAV, letting developers work against production or staging servers without a separate upload step.$q$, $q$Bluefish also supports regular expressions in search and replace, project management for organizing multi-file sites, Zencoding/Emmet-style markup shortcuts, and preconfigured integrations with external linting and markup validation tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bluefish is completely free software with no purchase price, subscription fee, or paid tier. It is licensed under the GNU General Public License, so it can be downloaded, used, modified, and redistributed at no cost.$q$, $q$Because Bluefish is a volunteer-maintained open-source project rather than a commercial product, there is no premium version, enterprise license, or paid support plan offered by its developers.$q$, $q$The only realistic costs associated with Bluefish come from the computer or Linux distribution it runs on, since Bluefish itself is bundled directly into many Linux package repositories at no additional charge.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a95891a-9b70-49b6-9aa5-aacb25ea2e3e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$UML-Style Class Diagram$q$, $q$Visualizes an application's classes and their relationships as an interactive, UML-like diagram.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Interactive Object Bench$q$, $q$Create objects directly from the class diagram and interact with them without writing a main method first.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Code Pad REPL$q$, $q$Evaluate Java (and now Kotlin) expressions instantly without compiling a full program.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Scope-Colored Code Editor$q$, $q$The source editor visually highlights nested code blocks to help beginners follow program structure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Direct Method Invocation$q$, $q$Call methods on live objects interactively and inspect their return values and internal state.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Integrated Debugger$q$, $q$A built-in debugger for stepping through code and inspecting program state during execution.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Kotlin Support$q$, $q$Version 6.0.0, released July 1, 2026, added Kotlin language support alongside Java.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Free and Open Source Licensing$q$, $q$Distributed under GPLv2 with the Classpath Exception at no cost for any number of installations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Completely free for schools, universities, and individual learners$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Purpose-built to make object-oriented programming concepts visible and interactive$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Widely adopted in secondary and university-level computer science curricula$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Endorsed publicly by Java creator James Gosling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Actively maintained, with Kotlin support added in version 6.0.0$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Not designed for large-scale production software development$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Fewer enterprise features and integrations than professional IDEs like IntelliJ IDEA or Eclipse$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Requires a 64-bit operating system for current releases, though a legacy 32-bit build exists$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Smaller plugin and extension ecosystem than mainstream commercial IDEs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Is BlueJ free?$q$, $q$Yes, BlueJ is completely free to download and use, distributed under the GNU General Public License version 2 with the Classpath Exception.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$What is BlueJ used for?$q$, $q$BlueJ is used primarily for teaching object-oriented programming, especially Java, by visualizing class structure and letting students interact directly with objects.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Who created BlueJ?$q$, $q$BlueJ was created by Michael Kolling and John Rosenberg, with development starting in 1999 at Monash University, and later strong ties to the University of Kent; it is now maintained by King's College London.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Does BlueJ support Kotlin?$q$, $q$Yes, as of version 6.0.0, released July 1, 2026, BlueJ added support for the Kotlin programming language alongside Java.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$What operating systems does BlueJ support?$q$, $q$BlueJ supports 64-bit Windows 8 or later, macOS 11 or later, and Ubuntu or Debian 20.04 or later; older 32-bit systems can use the legacy 4.1.4 release.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Is BlueJ good for beginners?$q$, $q$Yes, BlueJ was specifically designed for programming beginners, with features like an interactive object bench and scope-colored editor to simplify learning object-oriented concepts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Is BlueJ still maintained?$q$, $q$Yes, BlueJ continues to be actively maintained, with version 6.0.0 released July 1, 2026.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Does BlueJ replace a professional IDE like IntelliJ or Eclipse?$q$, $q$No, BlueJ is designed for teaching and learning rather than large-scale production development, so most learners move to a professional IDE like IntelliJ IDEA or Eclipse as their projects grow.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Teaching Introductory Programming$q$, $q$Instructors use BlueJ's visual class diagrams and interactive objects to teach object-oriented programming fundamentals in schools and universities.$q$, $q$Computer science instructors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Self-Directed Learning$q$, $q$Students learning Java or Kotlin independently use BlueJ's Code Pad and object bench to experiment with code without a full project setup.$q$, $q$Self-learners and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$Demonstrating OOP Concepts$q$, $q$Educators use BlueJ's UML-style diagrams and live object interaction to demonstrate class relationships and method calls in real time.$q$, $q$Educators and course designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$BlueJ$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Interactive object bench and class diagrams","Code Pad REPL","Integrated debugger","Kotlin and Java support","Unlimited installations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$overview$q$, $q$What Is BlueJ$q$, 2, ARRAY[$q$BlueJ is a free, education-focused integrated development environment for Java, built around visualizing class structure and letting students interact directly with objects while they learn to program. Development began in 1999 at Monash University by Michael Kolling and John Rosenberg, as a successor to an earlier teaching tool called Blue, with the first release on August 23, 1999.$q$, $q$BlueJ became closely tied to the University of Kent in the United Kingdom, where it supported introductory object-oriented programming courses, and is now maintained by King's College London with support from Oracle. James Gosling, the creator of the Java language, has publicly named BlueJ as one of his favorite IDEs.$q$, $q$Because BlueJ is aimed squarely at teaching, it deliberately simplifies parts of the software development workflow that full-scale professional IDEs make complex, prioritizing visual clarity and direct interaction with objects over the breadth of features found in tools like IntelliJ IDEA or Eclipse.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BlueJ's main window displays an application's classes as a UML-like diagram, and students can create objects directly from that diagram, inspect their internal state, call methods on them interactively, and pass objects as parameters, all without first writing a main method or test harness.$q$, $q$The Code Pad lets users evaluate Java expressions immediately without compiling a full program, functioning as a graphical shell or REPL for Java that is specifically suited to experimentation and learning. The source code editor includes scope coloring, which visually highlights nested code blocks to help beginners follow program structure.$q$, $q$As of version 6.0.0, released July 1, 2026, BlueJ added support for the Kotlin programming language alongside its original Java focus, broadening the languages instructors can teach with the same visual, object-interactive workflow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$BlueJ is completely free to download and use, with no purchase price, subscription, or commercial licensing tier. It is distributed under the GNU General Public License version 2 with the Classpath Exception, with copyright held by Michael Kolling and John Rosenberg.$q$, $q$Because it is free and open source, schools, universities, and individual learners can install BlueJ on an unlimited number of machines without licensing costs, which has been a significant factor in its widespread adoption in introductory programming courses.$q$, $q$BlueJ requires a 64-bit operating system, supporting Windows 8 or later, macOS 11 or later, and Ubuntu or Debian 20.04 or later; users on older 32-bit hardware can still run the free legacy 4.1.4 release.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40873439-74d5-4c5a-9d8b-5e7348a903a9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
