INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc8da50c-88b4-4b76-8a75-737643d423f5', $q$BlueChat$q$, $q$Built-in messaging that lets users chat alongside their email conversations.$q$, 2);
