INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc8da50c-88b4-4b76-8a75-737643d423f5', $q$Share Mail$q$, $q$Share individual emails publicly or privately with family, friends, or colleagues.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc8da50c-88b4-4b76-8a75-737643d423f5', $q$Cross-Platform Availability$q$, $q$Available on Android, iOS, Windows, macOS, Linux, and Amazon's app store, plus webmail access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc8da50c-88b4-4b76-8a75-737643d423f5', $q$Free for individuals with support for unlimited email accounts from any provider$q$, 0);
