INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$What does Bold Commerce do?$q$, $q$Bold Commerce builds e-commerce apps for Shopify merchants, including Bold Subscriptions, Bold Checkout, and Bold Upsell, focused on helping brands drive repeat purchases and higher order values.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Is Bold Commerce free?$q$, $q$Bold Subscriptions offers a free option for stores generating under 100 dollars per month in subscription revenue, with paid tiers starting at 24.99 dollars per month plus a transaction fee as revenue grows.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$How much does Bold Subscriptions cost?$q$, $q$Bold Subscriptions starts at 24.99 dollars per month plus a 2 percent transaction fee for stores under 2,500 dollars per month in subscription revenue, with custom Enterprise pricing above 1 million dollars in annual subscription revenue.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Does Bold Commerce work outside Shopify?$q$, $q$Bold Commerce's primary and best-known apps are built for the Shopify and Shopify Plus ecosystem; its composable commerce platform extends some capabilities beyond Shopify for larger enterprise customers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$What is Bold Checkout?$q$, $q$Bold Checkout is a customizable checkout app for Shopify Plus merchants designed to improve conversion rates during the checkout process.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Who founded Bold Commerce?$q$, $q$Bold Commerce was founded in 2012 in Winnipeg, Manitoba, by Jay Myers, Stefan Maynard, Eric Boisjoli, and Yvan Boisjoli.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$How many merchants use Bold Commerce apps?$q$, $q$Bold Commerce reports that more than 760,000 online merchants have installed apps it has built, with Bold Subscriptions alone powering over 41,000 subscription brands.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Is Bold Commerce Shopify Plus certified?$q$, $q$Yes, Bold Commerce is a Shopify Plus certified partner.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Launching a Subscription Program$q$, $q$Shopify merchants use Bold Subscriptions to set up recurring orders and subscription billing for consumable or replenishable products.$q$, $q$Shopify merchants adding subscriptions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$High-Conversion Checkout for Shopify Plus$q$, $q$Larger Shopify Plus brands use Bold Checkout to customize and optimize their checkout flow for higher conversion rates.$q$, $q$Shopify Plus enterprise brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Increasing Average Order Value$q$, $q$DTC brands use Bold Upsell and Bold Discounts together to run cart and post-purchase upsell campaigns alongside promotional pricing.$q$, $q$Direct-to-consumer e-commerce brands$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Bold Subscriptions Free$q$, $q$$0/month$q$, $q$Free (under $100/month in subscription revenue)$q$, NULL, $q$["Recurring order management","Basic subscription billing","90-day free trial option for new stores"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Bold Subscriptions Growth$q$, $q$$24.99/month + 2% transaction fee$q$, $q$Monthly (under $2,500/month in subscription revenue)$q$, NULL, $q$["Recurring order management","Subscription billing","Customer subscription portal"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$Bold Subscriptions Enterprise$q$, $q$Custom$q$, $q$Custom (over $1M/year in subscription revenue)$q$, NULL, $q$["Enterprise-scale subscription billing","Dedicated support","Custom configuration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$overview$q$, $q$What Is Bold Commerce$q$, 2, ARRAY[$q$Bold Commerce is an e-commerce technology company founded in 2012 in Winnipeg, Manitoba, Canada, by Jay Myers, Stefan Maynard, Eric Boisjoli, and Yvan Boisjoli. The company began by building apps to improve the Shopify merchant experience, starting with a product upsell tool, and has since grown into one of the longest-running third-party app developers on the Shopify platform.$q$, $q$Bold describes itself as 'the repeat commerce company,' focused on helping Shopify merchants generate more repeat purchases and higher customer lifetime value through subscriptions, upsells, discounts, and a customizable checkout. It remained bootstrapped until 2019, when it took on outside funding, including 35 million dollars backed by OMERS Ventures.$q$, $q$The company remains headquartered in Winnipeg and reports that more than 760,000 online merchants have installed apps it has built, making it one of the more established names in the Shopify app ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bold Commerce's core product suite includes Bold Subscriptions for recurring orders and subscription billing, Bold Checkout for a customizable and high-conversion Shopify checkout experience, and Bold Upsell for cart and post-purchase upsell offers.$q$, $q$Additional apps round out the suite: Bold Discounts for promotional pricing rules, Bold Custom Pricing for tiered or negotiated pricing, Bold Memberships for gated content and membership tiers, and rePete, a reorder-nudging tool that encourages customers to repurchase consumable products.$q$, $q$Bold holds Shopify Plus certification and positions itself as the first Shopify front-end app developer, reflecting deep, long-standing integration with the Shopify platform rather than a general-purpose e-commerce toolkit built for multiple platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3d6c369-5ccc-4a69-87aa-439e03e26dda', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bold Subscriptions offers a free option for stores generating under 100 dollars per month in subscription revenue, along with a 90-day free trial for new subscription businesses evaluating the product. The entry paid tier is 24.99 dollars per month plus a 2 percent transaction fee for stores with under 2,500 dollars per month in subscription revenue.$q$, $q$Pricing scales through additional tiers as a merchant's subscription revenue grows, with custom Enterprise pricing available for businesses generating over 1 million dollars in annual subscription revenue.$q$, $q$Bold's other apps, such as Checkout and Upsell, are generally priced and purchased separately through the Shopify App Store rather than bundled into a single Bold Commerce subscription, so total cost depends on which combination of apps a merchant adopts.$q$]::text[], 2);
